'use strict';

// 1. Initialize the store
const store = flow.get('metrics') || {};

/**
 * Classify topic into specific metric names
 */
function classify(topic) {
  const N = String(topic || '').trim().toUpperCase();

  // Default fallback
  let metric = 'generic_gauge';
  let help = 'Generic gauge';

  // --- LOGIC: Use .includes() or relaxed Regex to catch keywords ---

  // 1. CO2
  if (N.includes('.CO2.')) {
    metric = 'co2_ppm';
    help = 'CO2 concentration';
  }

  // 2. TEMPERATURE (Matches "TEMP.C" anywhere in the string)
  else if (N.includes('TEMP.C')) {
    metric = 'temperature_celsius';
    help = 'Air temperature';
  }

  // 3. HUMIDITY (Matches "RH.%" anywhere)
  else if (N.includes('RH.%')) {
    metric = 'humidity_percent';
    help = 'Relative humidity';
  }

  // 4. PRESSURE (Matches "P.HPA")
  else if (N.includes('P.HPA')) {
    // NOTE: Your Grafana looks for 'generic_gauge' for pressure. 
    // If you want to support that without changing Grafana, change the string below.
    metric = 'pressure_hpa';
    help = 'Atmospheric pressure';
  }

  // 5. POWER (Matches LEM.W or REM.W at start)
  else if (N.startsWith('LEM.W') || N.startsWith('REM.W')) {
    metric = 'power_watts';
    help = 'Active power';
  }

  // 6. AIR VELOCITY (Matches specific sensor names)
  else if (N.includes('LEE650AV') || N.includes('REE650AV')) {
    metric = 'air_velocity_mps';
    help = 'Air velocity';
  }

  // 7. GENERIC SENSORS
  else if (N.includes('LEE600') || N.includes('2A15')) {
    metric = 'sensor_value';
    help = 'Generic sensor value';
  }

  return { metric, help };
}

