            if (val === undefined || isNaN(val)) {
                node.warn("rightSliderPIDValue not set, defaulting to 0");
                val = 0;
            }
            val = Math.round(val);
            if (val < 0) val = 0;
            if (val > 55) val = 55;
        } else {
            node.error("No value provided for non-SP address", msg);
            return null;
        }
    }

    // Build Flex Write
    msg.payload = {
        fc: 6,
        unitid,
        address,     // zero-based offset
        quantity: 1,
        value: [ val ]
    };

    node.status({ fill: "green", shape: "dot", text: `Write ${val} @U${unitid}:${address}` });
